/// Result of a visitor callback.
///
/// Allows visitors to control the conversion flow by either proceeding
/// with default behavior, providing custom output, skipping elements,
/// preserving HTML, or signaling errors.
pub const VisitResult = union(enum) {
    /// Continue with default conversion behavior
    continue_: void,
    /// Replace default output with custom markdown
    ///
    /// The visitor takes full responsibility for the markdown output
    /// of this node and its children.
    custom: []const u8,
    /// Skip this element entirely (don't output anything)
    ///
    /// The element and all its children are ignored in the output.
    skip: void,
    /// Preserve original HTML (don't convert to markdown)
    ///
    /// The element's raw HTML is included verbatim in the output.
    preserve_html: void,
    /// Stop conversion with an error
    ///
    /// The conversion process halts and returns this error message.
    error_: []const u8,
};

/// Convert HTML to Markdown, returning a `ConversionResult` with content, metadata, images,
/// and warnings.
///
///   `impl Into<Option<ConversionOptions>>`, so any of the following call shapes are accepted:
///
///   - `convert(html, ConversionOptions.default())` — bare options.
///   - `convert(html, opts)` — bare options.
///   - `convert(html, Some(opts))` — explicit `Option`.
///   - `convert(html, None)` — fall back to `ConversionOptions.default`.
///
/// **Errors:**
///
/// Returns an error if HTML parsing fails or if the input contains invalid UTF-8.
pub fn convert(html: []const u8, options: ?[]const u8) ConversionError![]u8 {
    const html_z = try std.fmt.allocPrintSentinel(std.heap.c_allocator, "{s}", .{html}, 0);
    defer std.heap.c_allocator.free(html_z);
    const options_z: ?[:0]u8 = if (options) |v| try std.fmt.allocPrintSentinel(std.heap.c_allocator, "{s}", .{v}, 0) else null;
    defer if (options_z) |z| std.heap.c_allocator.free(z);
    const options_handle = if (options_z) |z| c.htm_conversion_options_from_json(z) else null;
    if (options_z != null and options_handle == null) return _first_error(ConversionError);
    defer if (options_handle) |h| c.htm_conversion_options_free(h);
    const _result = c.htm_convert(html_z, options_handle);
    if (c.htm_last_error_code() != 0) {
        return _first_error(ConversionError);
    }
    if (_result == null) {
        return _first_error(ConversionError);
    }
    return blk: {
        const _json_ptr = c.htm_conversion_result_to_json(_result.?);
        defer _free_string(_json_ptr);
        c.htm_conversion_result_free(_result.?);
        const slice = std.mem.sliceTo(_json_ptr, 0);
        const owned = try std.heap.c_allocator.dupe(u8, slice);
        break :blk owned;
    };
}

/// Vtable for a Zig implementation of the `HtmlVisitor` trait.
/// Fill each function pointer, then pass this struct to the corresponding
/// `register_html_visitor` function to register your implementation.
pub const IHtmlVisitor = extern struct {
    /// Visit text nodes (most frequent callback - ~100+ per document).
    ///
    /// # Arguments
    /// - `ctx`: Node context (will have `node_type: NodeType::Text`)
    /// - `text`: The raw text content (HTML entities already decoded)
    visit_text: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _text: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Called before entering any element.
    ///
    /// This is the first callback invoked for every HTML element, allowing
    /// visitors to implement generic element handling before tag-specific logic.
    visit_element_start: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Called after exiting any element.
    ///
    /// Receives the default markdown output that would be generated.
    /// Visitors can inspect or replace this output.
    visit_element_end: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _output: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Visit anchor links `<a href="...">`.
    ///
    /// # Arguments
    /// - `ctx`: Node context with link element metadata
    /// - `href`: The link URL (from `href` attribute)
    /// - `text`: The link text content (already converted to markdown)
    /// - `title`: Optional title attribute
    visit_link: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _href: [*c]const u8, _text: [*c]const u8, _title: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Visit images `<img src="...">`.
    ///
    /// # Arguments
    /// - `ctx`: Node context with image element metadata
    /// - `src`: The image source URL
    /// - `alt`: The alt text
    /// - `title`: Optional title attribute
    visit_image: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _src: [*c]const u8, _alt: [*c]const u8, _title: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Visit heading elements `<h1>` through `<h6>`.
    ///
    /// # Arguments
    /// - `ctx`: Node context with heading metadata
    /// - `level`: Heading level (1-6)
    /// - `text`: The heading text content
    /// - `id`: Optional id attribute (for anchor links)
    visit_heading: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _level: u32, _text: [*c]const u8, _id: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Visit code blocks `<pre><code>`.
    ///
    /// # Arguments
    /// - `ctx`: Node context
    /// - `lang`: Optional language specifier (from class attribute)
    /// - `code`: The code content
    visit_code_block: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _lang: [*c]const u8, _code: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Visit inline code `<code>`.
    ///
    /// # Arguments
    /// - `ctx`: Node context
    /// - `code`: The code content
    visit_code_inline: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _code: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Visit list items `<li>`.
    ///
    /// # Arguments
    /// - `ctx`: Node context
    /// - `ordered`: Whether this is an ordered list item
    /// - `marker`: The list marker (e.g., "-", "1.", "a)")
    /// - `text`: The list item content (already converted)
    visit_list_item: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _ordered: i32, _marker: [*c]const u8, _text: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Called before processing a list `<ul>` or `<ol>`.
    visit_list_start: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _ordered: i32, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Called after processing a list `</ul>` or `</ol>`.
    visit_list_end: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, _ordered: i32, _output: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Called before processing a table `<table>`.
    visit_table_start: ?*const fn (user_data: ?*anyopaque, _ctx: [*c]const u8, out_result: ?*?[*c]u8) callconv(.c) i32 = null,
    /// Visit table rows `<tr>`.
    ///
    /// # Arguments
